import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized string for the current locale.
///
/// Used for parameter labels and option descriptions.
typedef LocalizedText = String Function(AppLocalizations l10n);

/// The data type of a fractal parameter.
///
/// Determines how the parameter is rendered in the UI and how its
/// value is validated and stored.
enum FractalParamType {
  /// A floating-point number parameter.
  ///
  /// Rendered as a slider with continuous values.
  /// Value type: [double]
  float,

  /// An integer parameter.
  ///
  /// Rendered as a slider with discrete steps.
  /// Value type: [int]
  integer,

  /// A selection from a fixed set of options.
  ///
  /// Rendered as a dropdown or segmented control.
  /// Value type: depends on [FractalParamOption.value]
  enumeration,

  /// A boolean on/off parameter.
  ///
  /// Rendered as a switch or checkbox.
  /// Value type: [bool]
  boolean,
}

/// An option for an enumeration-type parameter.
///
/// Defines a single selectable value with its display label.
///
/// Example:
/// ```dart
/// FractalParamOption(
///   value: 0,
///   label: (l10n) => l10n.colorFire,
/// )
/// ```
class FractalParamOption {
  /// The underlying value for this option.
  ///
  /// This is what gets stored in the parameter map and passed to shaders.
  final Object value;

  /// Returns the localized display label for this option.
  final LocalizedText label;

  /// Creates a new parameter option.
  const FractalParamOption({
    required this.value,
    required this.label,
  });
}

/// Defines the schema for a configurable fractal parameter.
///
/// A [FractalParameter] describes how a single adjustable value should
/// behave: its valid range, step increment, default value, and UI
/// representation.
///
/// Parameters are defined per [FractalModule] and used to:
/// - Generate the controls UI automatically
/// - Validate user input
/// - Clamp values to valid ranges
/// - Store and restore presets
///
/// {@category Models}
///
/// Example:
/// ```dart
/// FractalParameter(
///   id: 'iterations',
///   label: (l10n) => l10n.paramIterations,
///   type: FractalParamType.integer,
///   min: 10,
///   max: 500,
///   step: 1,
///   defaultValue: 100,
/// )
/// ```
@immutable
class FractalParameter {
  /// Unique identifier for this parameter.
  ///
  /// Used as the key in parameter maps and for preset serialization.
  /// Should be a lowercase, camelCase string (e.g., 'iterations', 'colorScheme').
  final String id;

  /// Returns the localized display label for this parameter.
  ///
  /// Shown in the controls UI next to the input widget.
  final LocalizedText label;

  /// The data type of this parameter.
  ///
  /// Determines the UI widget and value handling.
  final FractalParamType type;

  /// The minimum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration] and [FractalParamType.boolean],
  /// this is typically 0.
  final double min;

  /// The maximum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration], this should match `options.length - 1`.
  final double max;

  /// The step increment for slider-based inputs.
  ///
  /// For integers, use 1.0. For floats, use an appropriate precision
  /// (e.g., 0.1 or 0.01).
  final double step;

  /// The initial value when no preset is applied.
  ///
  /// Must be within the [min]/[max] range and compatible with [type].
  final Object defaultValue;

  /// Available options for enumeration-type parameters.
  ///
  /// Only used when [type] is [FractalParamType.enumeration].
  /// Empty for other types.
  final List<FractalParamOption> options;

  /// Creates a new [FractalParameter] with the specified schema.
  ///
  /// For enumeration types, ensure [options] is populated with
  /// all valid choices.
  const FractalParameter({
    required this.id,
    required this.label,
    required this.type,
    required this.min,
    required this.max,
    required this.step,
    required this.defaultValue,
    this.options = const [],
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 rotation;

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 mousePos;

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  const FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required this.rotation,
    this.colorScheme = 0,
    required this.mousePos,
    this.fractalType = FractalType.mandelbulb,
  });

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? this.mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        rotation,
        colorScheme,
        mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  const FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required this.params,
    required this.view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  });

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
  }) {
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath: thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map).map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ?? DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset = FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'package:vector_math/vector_math.dart';

/// Represents the view/camera state for fractal rendering.
///
/// This class captures the user's navigation state within a fractal:
/// - For 2D fractals: pan offset and zoom level
/// - For 3D fractals: rotation angles and zoom level
///
/// [FractalViewState] is designed to be stored in presets and serialized,
/// allowing users to save and restore specific viewpoints.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final view = FractalViewState(
///   pan: Vector2(-0.5, 0.2),  // Offset from center
///   zoom: 3.0,                 // 3x magnification
///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 pan;

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 rotation;

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state.
  const FractalViewState({
    required this.pan,
    required this.zoom,
    required this.rotation,
  });

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : pan = Vector2.zero(),
        zoom = 1.0,
        rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? this.pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
    );
  }
}

import 'dart:convert';

import 'package:flutter/material.dart';

@immutable
class FractalColorStop {
  final double position; // 0..1
  final int colorArgb; // 0xAARRGGBB

  const FractalColorStop({
    required this.position,
    required this.colorArgb,
  });

  Color get color => Color(colorArgb);

  FractalColorStop copyWith({
    double? position,
    int? colorArgb,
  }) {
    return FractalColorStop(
      position: position ?? this.position,
      colorArgb: colorArgb ?? this.colorArgb,
    );
  }

  Map<String, Object?> toJson() => {
        'p': position,
        'c': colorArgb,
      };

  static FractalColorStop fromJson(Map<String, Object?> json) {
    final p = (json['p'] as num?)?.toDouble() ?? 0.0;
    final c = (json['c'] as num?)?.toInt() ?? 0xFFFFFFFF;
    return FractalColorStop(position: p, colorArgb: c);
  }
}

@immutable
class FractalPalette {
  final String id;
  final String name;
  final List<FractalColorStop> stops;
  final bool isBuiltIn;

  const FractalPalette({
    required this.id,
    required this.name,
    required this.stops,
    this.isBuiltIn = false,
  });

  FractalPalette copyWith({
    String? id,
    String? name,
    List<FractalColorStop>? stops,
    bool? isBuiltIn,
  }) {
    return FractalPalette(
      id: id ?? this.id,
      name: name ?? this.name,
      stops: stops ?? this.stops,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
    );
  }

  LinearGradient toLinearGradient() {
    final sorted = [...stops]..sort((a, b) => a.position.compareTo(b.position));
    return LinearGradient(
      colors: sorted.map((s) => s.color).toList(),
      stops: sorted.map((s) => s.position.clamp(0.0, 1.0)).toList(),
    );
  }

  Map<String, Object?> toJson() => {
        'id': id,
        'name': name,
        'stops': stops.map((s) => s.toJson()).toList(),
      };

  static FractalPalette fromJson(Map<String, Object?> json) {
    final id = (json['id'] as String?) ?? '';
    final name = (json['name'] as String?) ?? 'Palette';
    final rawStops = (json['stops'] as List?) ?? const [];
    final stops = rawStops
        .whereType<Map>()
        .map((m) => FractalColorStop.fromJson(m.cast<String, Object?>()))
        .toList();

    return FractalPalette(
      id: id,
      name: name,
      stops: stops,
      isBuiltIn: false,
    );
  }

  String toJsonString({bool pretty = true}) {
    final map = toJson();
    return pretty
        ? const JsonEncoder.withIndent('  ').convert(map)
        : jsonEncode(map);
  }

  static FractalPalette fromJsonString(String input) {
    final decoded = jsonDecode(input);
    if (decoded is! Map) {
      throw const FormatException('Palette JSON must be an object');
    }
    return FractalPalette.fromJson(decoded.cast<String, Object?>());
  }
}

import 'package:equatable/equatable.dart';

/// Supported export image formats
enum ExportFormat {
  png,
  jpg,
  webp,
}

extension ExportFormatExtension on ExportFormat {
  String get extension {
    switch (this) {
      case ExportFormat.png:
        return 'png';
      case ExportFormat.jpg:
        return 'jpg';
      case ExportFormat.webp:
        return 'webp';
    }
  }

  String get mimeType {
    switch (this) {
      case ExportFormat.png:
        return 'image/png';
      case ExportFormat.jpg:
        return 'image/jpeg';
      case ExportFormat.webp:
        return 'image/webp';
    }
  }

  String get displayName {
    switch (this) {
      case ExportFormat.png:
        return 'PNG';
      case ExportFormat.jpg:
        return 'JPG';
      case ExportFormat.webp:
        return 'WebP';
    }
  }
}

/// Preset resolution options for export
enum ExportResolution {
  screen, // Current screen resolution
  hd, // 1280x720
  fullHd, // 1920x1080
  quadHd, // 2560x1440
  uhd4k, // 3840x2160
  instagram, // 1080x1080 (square)
  instagramStory, // 1080x1920 (9:16)
  twitter, // 1200x675 (16:9)
  custom,
}

extension ExportResolutionExtension on ExportResolution {
  String get displayName {
    switch (this) {
      case ExportResolution.screen:
        return 'Screen';
      case ExportResolution.hd:
        return 'HD (1280×720)';
      case ExportResolution.fullHd:
        return 'Full HD (1920×1080)';
      case ExportResolution.quadHd:
        return '2K (2560×1440)';
      case ExportResolution.uhd4k:
        return '4K (3840×2160)';
      case ExportResolution.instagram:
        return 'Instagram (1080×1080)';
      case ExportResolution.instagramStory:
        return 'Instagram Story (1080×1920)';
      case ExportResolution.twitter:
        return 'Twitter (1200×675)';
      case ExportResolution.custom:
        return 'Custom';
    }
  }

  /// Returns (width, height) for preset resolutions
  /// Returns null for screen (use device size) or custom (user specified)
  (int, int)? get dimensions {
    switch (this) {
      case ExportResolution.screen:
        return null;
      case ExportResolution.hd:
        return (1280, 720);
      case ExportResolution.fullHd:
        return (1920, 1080);
      case ExportResolution.quadHd:
        return (2560, 1440);
      case ExportResolution.uhd4k:
        return (3840, 2160);
      case ExportResolution.instagram:
        return (1080, 1080);
      case ExportResolution.instagramStory:
        return (1080, 1920);
      case ExportResolution.twitter:
        return (1200, 675);
      case ExportResolution.custom:
        return null;
    }
  }

  bool get isSocialPreset {
    return this == ExportResolution.instagram ||
        this == ExportResolution.instagramStory ||
        this == ExportResolution.twitter;
  }
}

/// Metadata to embed in exported images
class ExportMetadata extends Equatable {
  final String? title;
  final String? description;
  final String fractalType;
  final Map<String, Object> parameters;
  final DateTime createdAt;
  final String appVersion;

  const ExportMetadata({
    this.title,
    this.description,
    required this.fractalType,
    required this.parameters,
    required this.createdAt,
    this.appVersion = '1.0.0',
  });

  Map<String, String> toExifMap() {
    return {
      'Software': 'Flutter Fractals $appVersion',
      'ImageDescription':
          description ?? 'Fractal artwork created with Flutter Fractals',
      'Artist': 'Flutter Fractals',
      'Copyright': '© ${createdAt.year} Flutter Fractals',
      'UserComment': _buildUserComment(),
    };
  }

  String _buildUserComment() {
    final buffer = StringBuffer();
    buffer.writeln('Fractal Type: $fractalType');
    buffer.writeln('Created: ${createdAt.toIso8601String()}');
    buffer.writeln('Parameters:');
    for (final entry in parameters.entries) {
      buffer.writeln('  ${entry.key}: ${entry.value}');
    }
    return buffer.toString();
  }

  @override
  List<Object?> get props =>
      [title, description, fractalType, parameters, createdAt, appVersion];
}

/// Complete export configuration
class ExportOptions extends Equatable {
  final ExportFormat format;
  final ExportResolution resolution;
  final int? customWidth;
  final int? customHeight;
  final bool transparentBackground;
  final int quality; // 1-100, for JPG/WebP
  final bool embedMetadata;
  final ExportMetadata? metadata;
  final bool addWatermark;
  final String? watermarkText;

  const ExportOptions({
    this.format = ExportFormat.png,
    this.resolution = ExportResolution.fullHd,
    this.customWidth,
    this.customHeight,
    this.transparentBackground = false,
    this.quality = 95,
    this.embedMetadata = true,
    this.metadata,
    this.addWatermark = false,
    this.watermarkText,
  });

  (int, int)? _orientedPresetDimensions(
      double screenWidth, double screenHeight) {
    final dims = resolution.dimensions;
    if (dims == null) return null;

    final width = dims.$1;
    final height = dims.$2;
    final isPresetSquare = width == height;
    if (isPresetSquare) return dims;

    final screenPortrait = screenHeight > screenWidth;
    final presetPortrait = height > width;

    if (screenPortrait != presetPortrait) {
      return (height, width);
    }

    return dims;
  }

  /// Calculate the pixel ratio needed to achieve target resolution
  double calculatePixelRatio(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      // Use the larger ratio to ensure we meet target resolution
      final widthRatio = dims.$1 / screenWidth;
      final heightRatio = dims.$2 / screenHeight;
      // Use max to ensure we hit the target resolution on both axes
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    if (resolution == ExportResolution.custom) {
      final widthRatio = (customWidth ?? screenWidth.round()) / screenWidth;
      final heightRatio = (customHeight ?? screenHeight.round()) / screenHeight;
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    return 2.5; // Default for screen resolution
  }

  /// Get the target dimensions for this export
  (int, int) getTargetDimensions(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      return dims;
    }

    if (resolution == ExportResolution.custom) {
      return (
        customWidth ?? screenWidth.round(),
        customHeight ?? screenHeight.round(),
      );
    }

    // Screen resolution
    return (screenWidth.round(), screenHeight.round());
  }

  ExportOptions copyWith({
    ExportFormat? format,
    ExportResolution? resolution,
    int? customWidth,
    int? customHeight,
    bool? transparentBackground,
    int? quality,
    bool? embedMetadata,
    ExportMetadata? metadata,
    bool? addWatermark,
    String? watermarkText,
  }) {
    return ExportOptions(
      format: format ?? this.format,
      resolution: resolution ?? this.resolution,
      customWidth: customWidth ?? this.customWidth,
      customHeight: customHeight ?? this.customHeight,
      transparentBackground:
          transparentBackground ?? this.transparentBackground,
      quality: quality ?? this.quality,
      embedMetadata: embedMetadata ?? this.embedMetadata,
      metadata: metadata ?? this.metadata,
      addWatermark: addWatermark ?? this.addWatermark,
      watermarkText: watermarkText ?? this.watermarkText,
    );
  }

  @override
  List<Object?> get props => [
        format,
        resolution,
        customWidth,
        customHeight,
        transparentBackground,
        quality,
        embedMetadata,
        metadata,
        addWatermark,
        watermarkText,
      ];
}

